module gray_counter(clk, rst, gray);

    input clk;
    input rst;
    output [4:0] gray;
    reg [4:0] unused_bin;
    reg [4:0] gray;

    always @(posedge clk)
    begin
        if (rst)
            unused_bin <= 5'b00000;
        else
            unused_bin <= unused_bin + 1;
    end

    always @(*)
    begin
        gray = unused_bin ^ (unused_bin >> 1);
    end

endmodule
